SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/domains/flows/validate-domain-quality.yaml`] = `flow:
  id: validate-domain-quality
  name: Validate Domain Quality
  type: traditional
  domain: domains
  description: |
    Run 3 automated quality tests on domain models:
    1. Specificity: Concepts must be domain-specific
    2. Distinctiveness: Quality principles must produce different evaluation criteria
    3. Anti-pattern specificity: Anti-patterns must be domain-specific

trigger:
  id: trigger-validate
  type: api_endpoint
  position: { x: 400, y: 50 }
  connections:
    - targetNodeId: load-domain
  spec:
    method: POST
    path: "/api/v1/domains/{id}/validate"
    description: Validate domain quality before use
  label: POST /domains/{id}/validate

nodes:
  - id: load-domain
    type: data_store
    position: { x: 400, y: 150 }
    connections:
      - targetNodeId: test-specificity
        sourceHandle: success
      - targetNodeId: terminal-not-found
        sourceHandle: error
    spec:
      operation: read
      model: DomainModel
      query:
        id: "\$.params.id"
      description: Load domain for validation
    label: Load Domain

  - id: terminal-not-found
    type: terminal
    position: { x: 650, y: 150 }
    connections: []
    spec:
      outcome: error
      error_code: NOT_FOUND
      http_status: 404
    label: Not Found

  # TEST 1: SPECIFICITY
  - id: test-specificity
    type: service_call
    position: { x: 400, y: 280 }
    connections:
      - targetNodeId: test-distinctiveness
    spec:
      method: POST
      url: "http://domains-service/test-specificity"
      body:
        domain_id: "\$.domain.id"
        core_concepts: "\$.domain.core_concepts"
      description: Test if concepts are domain-specific (not generic)
    label: Test Specificity

  # TEST 2: DISTINCTIVENESS
  - id: test-distinctiveness
    type: service_call
    position: { x: 400, y: 410 }
    connections:
      - targetNodeId: test-antipattern-specificity
    spec:
      method: POST
      url: "http://domains-service/test-distinctiveness"
      body:
        domain_id: "\$.domain.id"
        quality_principles: "\$.domain.quality_principles"
        other_domains: "\$.other_domains"
      description: Test if quality principles produce distinct evaluation criteria
    label: Test Distinctiveness

  # TEST 3: ANTI-PATTERN SPECIFICITY
  - id: test-antipattern-specificity
    type: service_call
    position: { x: 400, y: 540 }
    connections:
      - targetNodeId: aggregate-results
    spec:
      method: POST
      url: "http://domains-service/test-anti-pattern-specificity"
      body:
        domain_id: "\$.domain.id"
        anti_patterns: "\$.domain.anti_patterns"
      description: Test if anti-patterns are domain-specific
    label: Test Anti-Pattern Specificity

  # AGGREGATE AND DECIDE
  - id: aggregate-results
    type: service_call
    position: { x: 400, y: 670 }
    connections:
      - targetNodeId: decide-pass-fail
    spec:
      method: POST
      url: "http://domains-service/aggregate-quality-results"
      body:
        specificity_result: "\$.specificity_test"
        distinctiveness_result: "\$.distinctiveness_test"
        antipattern_result: "\$.antipattern_test"
      description: Combine test results
    label: Aggregate Results

  - id: decide-pass-fail
    type: decision
    position: { x: 400, y: 800 }
    connections:
      - targetNodeId: update-passed
        sourceHandle: true
      - targetNodeId: update-failed
        sourceHandle: false
    spec:
      condition: "\$.aggregated_result.failures_count < 2"
      description: Pass if fewer than 2 tests failed
    label: Passed >=2 Tests?

  - id: update-passed
    type: data_store
    position: { x: 250, y: 930 }
    connections:
      - targetNodeId: event-validated
    spec:
      operation: update
      model: DomainModel
      query:
        id: "\$.domain.id"
      data:
        quality_test_passed: true
        quality_test_results: "\$.aggregated_result"
        quality_test_failures: []
      description: Update domain as quality-passed
    label: Update Passed

  - id: update-failed
    type: data_store
    position: { x: 550, y: 930 }
    connections:
      - targetNodeId: event-validated
    spec:
      operation: update
      model: DomainModel
      query:
        id: "\$.domain.id"
      data:
        quality_test_passed: false
        quality_test_results: "\$.aggregated_result"
        quality_test_failures: "\$.aggregated_result.failed_tests"
      description: Update domain as quality-failed
    label: Update Failed

  - id: event-validated
    type: event
    position: { x: 400, y: 1060 }
    connections:
      - targetNodeId: terminal-success
    spec:
      direction: emit
      event_name: DomainQualityAssessed
      payload:
        domain_id: "\$.domain.id"
        passed: "\$.quality_test_passed"
        failures: "\$.quality_test_failures"
      async: true
      description: Emit quality assessment event
    label: Emit DomainQualityAssessed

  - id: terminal-success
    type: terminal
    position: { x: 400, y: 1190 }
    connections: []
    spec:
      outcome: success
      http_status: 200
      description: Quality validation complete
      body:
        domain_id: "\$.domain.id"
        passed: "\$.quality_test_passed"
        test_results: "\$.aggregated_result"
        failures: "\$.quality_test_failures"
        badge: "Passed ? 'community_verified' : 'community_new'"
    label: Success

metadata:
  created: "2026-03-18T00:00:00Z"
  modified: "2026-03-18T00:00:00Z"
`;

