SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/intelligence/flows/triage-signals.yaml`] = `flow:
  id: triage-signals
  name: Triage Signals
  type: traditional
  domain: intelligence
  description: |
    Filter signals by relevance, credibility tier, temporal validity, and deduplication.
    Returns triaged signals and metrics for analysis quality assessment.

trigger:
  id: trigger-triage
  type: api_endpoint
  position: { x: 400, y: 50 }
  connections:
    - targetNodeId: validate-input
  spec:
    method: POST
    path: "/api/v1/signals/triage"
    description: Triage signals for analysis
  label: POST /signals/triage

nodes:
  - id: validate-input
    type: decision
    position: { x: 400, y: 150 }
    connections:
      - targetNodeId: filter-credibility
        sourceHandle: "true"
      - targetNodeId: terminal-invalid
        sourceHandle: "false"
    spec:
      condition: "\$.body.signals.length > 0"
      description: Has signals to triage
    label: Signals Present?

  - id: terminal-invalid
    type: terminal
    position: { x: 650, y: 150 }
    connections: []
    spec:
      outcome: error
      error_code: VALIDATION_ERROR
      http_status: 422
    label: Invalid Input

  # FILTER 1: CREDIBILITY TIER
  - id: filter-credibility
    type: collection
    position: { x: 400, y: 280 }
    connections:
      - targetNodeId: filter-temporal
    spec:
      operation: filter
      input: "\$.body.signals"
      predicate: "signal.credibility_tier in \$.credibility_config.accepted_tiers"
      output: "credibility_passed"
      description: Filter by credibility tier
    label: Filter Credibility Tier

  - id: track-rejection
    type: service_call
    position: { x: 250, y: 280 }
    connections:
      - targetNodeId: filter-temporal
    spec:
      method: POST
      url: "http://intelligence-service/track-rejection"
      body:
        analysis_id: "\$.analysis_id"
        rejected_signals: "\$.body.signals[*] - \$.credibility_passed"
        reason: "low_credibility"
      description: Track rejected signals
    label: Track Rejections

  # FILTER 2: TEMPORAL VALIDITY
  - id: filter-temporal
    type: collection
    position: { x: 400, y: 410 }
    connections:
      - targetNodeId: filter-duplicates
    spec:
      operation: filter
      input: "\$.credibility_passed"
      predicate: "now() - signal.published_at <= signal.temporal_validity"
      output: "temporal_passed"
      description: Filter out stale signals
    label: Filter Temporal Validity

  # FILTER 3: DEDUPLICATION
  - id: filter-duplicates
    type: collection
    position: { x: 400, y: 540 }
    connections:
      - targetNodeId: assess-relevance
    spec:
      operation: deduplicate
      input: "\$.temporal_passed"
      key: "signal.url"
      output: "unique_signals"
      description: Deduplicate by URL
    label: Deduplicate by URL

  # FILTER 4: RELEVANCE (AI-powered)
  - id: assess-relevance
    type: service_call
    position: { x: 400, y: 670 }
    connections:
      - targetNodeId: filter-relevance
    spec:
      method: POST
      url: "http://intelligence-service/assess-relevance"
      timeout_ms: 30000
      body:
        signals: "\$.unique_signals"
        question: "\$.question"
        domain_concepts: "\$.domain_concepts"
      description: AI assesses relevance of each signal
    label: Assess Relevance

  - id: filter-relevance
    type: collection
    position: { x: 400, y: 800 }
    connections:
      - targetNodeId: calculate-metrics
    spec:
      operation: filter
      input: "\$.unique_signals"
      predicate: "signal.relevance_score >= 0.6"
      output: "relevant_signals"
      description: Keep signals with relevance >= 0.6
    label: Filter Relevance

  # CALCULATE METRICS
  - id: calculate-metrics
    type: service_call
    position: { x: 400, y: 930 }
    connections:
      - targetNodeId: update-signal-status
    spec:
      method: POST
      url: "http://intelligence-service/calculate-triage-metrics"
      body:
        raw_count: "\$.body.signals.length"
        pass_count: "\$.relevant_signals.length"
        failures:
          credibility: "\$.body.signals.length - \$.credibility_passed.length"
          temporal: "\$.credibility_passed.length - \$.temporal_passed.length"
          duplicates: "\$.temporal_passed.length - \$.unique_signals.length"
          relevance: "\$.unique_signals.length - \$.relevant_signals.length"
      description: Calculate triage ratio and failure breakdown
    label: Calculate Metrics

  - id: update-signal-status
    type: data_store
    position: { x: 400, y: 1060 }
    connections:
      - targetNodeId: terminal-success
    spec:
      operation: update_many
      model: Signal
      query:
        id: "in \$.relevant_signals[*].id"
      data:
        status: "signal"
      description: Mark passed signals as triaged
    label: Update Signal Status

  - id: terminal-success
    type: terminal
    position: { x: 400, y: 1190 }
    connections: []
    spec:
      outcome: success
      http_status: 200
      description: Signals triaged successfully
      body:
        analysis_id: "\$.analysis_id"
        domain_id: "\$.domain_id"
        raw_count: "\$.metrics.raw_count"
        pass_count: "\$.metrics.pass_count"
        triage_ratio: "\$.metrics.triage_ratio"
        signals: "\$.relevant_signals"
        failure_breakdown: "\$.metrics.failures"
    label: Success

metadata:
  created: "2026-03-18T00:00:00Z"
  modified: "2026-03-18T00:00:00Z"
`;

